import { BaseActivityData } from './core';
import { WordSearchData, MissingPartsData } from './visual';

export * from './core';

export interface StoryQuestion {
    type: 'multiple-choice' | 'open-ended' | 'true-false' | 'logic' | 'vocabulary' | 'inference' | 'bloom_analysis' | 'bloom_synthesis';
    question: string;
    options?: string[]; 
    answer?: string;
    isTrue?: boolean;
    difficultyLevel?: 'easy' | 'medium' | 'hard';
    sentence?: string; // For fill in blank
}

export interface VocabularyItem {
    word: string;
    definition: string;
}

export interface StoryData extends BaseActivityData {
    story: string;
    mainIdea: string;
    characters: string[];
    setting: string;
    vocabulary: VocabularyItem[];
    creativeTask: string;
    questions: StoryQuestion[];
}

export interface StoryAnalysisData extends BaseActivityData {
    story: string;
    storyMap: {
        characters: string;
        setting: string;
        problem: string;
        solution: string;
        theme: string;
    };
}

export interface StoryCreationPromptData extends BaseActivityData {
    prompt: string;
    keywords: string[];
    structureHints: {
        who: string;
        where: string;
        when: string;
        problem: string;
    };
}

export interface WordsInStoryData extends BaseActivityData {
    story: string;
    vocabWork: {
        word: string;
        contextQuestion: string;
        type: 'meaning' | 'usage';
    }[];
}

export interface StorySequencingData extends BaseActivityData {
    prompt: string;
    panels: {
        id: string;
        description: string;
        order: number;
        imagePrompt?: string;
    }[];
    transitionWords?: string[];
}

export interface InteractiveStoryData extends BaseActivityData { 
    story: string; 
    segments: { id: string; text: string; }[]; 
    genre: string;
    gradeLevel: string;
    wordCount: number;

    // Bloom Taxonomy & Intervention Components
    fiveW1H: { question: string; answer: string; type: string }[];
    multipleChoice: { question: string; options: string[]; answer: string }[];
    trueFalse: { question: string; answer: boolean }[];
    fillBlanks: { sentence: string; answer: string }[];
    logicQuestions: { question: string; answer: string; hint: string }[];
    inferenceQuestions: { question: string; answer: string }[]; 
    interventionQuestions: { question: string; type: 'word_hunt' | 'spelling' | 'visual_memory' }[];

    vocabulary: VocabularyItem[]; 
    creativeTask: string; 
    mainIdea: string;
    imagePrompt: string;
    answers?: any[];
}

// Proverb Specific Aliases/Interfaces
export interface ProverbFillData extends MissingPartsData {}
export interface ProverbSayingSortData extends StoryData {}
export interface ProverbWordChainData extends StorySequencingData {}
export interface ProverbSentenceFinderData extends StorySequencingData {}
export interface ProverbSearchData extends WordSearchData {}

export interface ReadingStudioConfig {
    gradeLevel: string;
    studentName: string;
    topic: string;
    genre: string;
    tone: string;

    // Text Content Settings
    length: 'short' | 'medium' | 'long' | 'epic';
    textComplexity: 'simple' | 'moderate' | 'advanced';

    // Typography & Accessibility (Visual Settings)
    fontSettings: {
        family: 'OpenDyslexic' | 'Lexend' | 'Comic Neue' | 'Times New Roman';
        size: number;
        lineHeight: number;
        letterSpacing: number;
        wordSpacing: number;
    };

    layoutDensity: 'comfortable' | 'compact';

    // Image Advanced Controls
    includeImage: boolean;
    imageSize: number; 
    imagePosition: 'top' | 'left' | 'right' | 'center' | 'background';
    imageOpacity: number;

    // Bloom Taxonomy Structure
    include5N1K: boolean;
    countMultipleChoice: number;
    countTrueFalse: number;
    countFillBlanks: number;
    countLogic: number;
    countInference: number;

    // Intervention Modules
    includeWordHunt: boolean;
    includeSpellingCheck: boolean;
    focusVocabulary: boolean;
    includeCreativeTask: boolean;

    // UI Modules
    showReadingTracker: boolean;
    showSelfAssessment: boolean;
    showTeacherNotes: boolean;
    showDateSection: boolean;
}

export type LayoutSectionId = 'header' | 'tracker' | 'story_block' | 'vocabulary' | 'questions_5n1k' | 'questions_test' | 'questions_inference' | 'creative' | 'self_eval' | 'notes';

// Updated for Absolute Positioning Canvas
export interface LayoutItemStyle {
    // Positioning
    x: number;
    y: number;
    w: number;
    h: number;
    zIndex: number;

    // Visuals
    backgroundColor?: string;
    borderColor?: string;
    borderWidth?: number;
    borderRadius?: number;
    boxShadow?: string; // 'none', 'sm', 'md', 'lg'
    opacity?: number;

    // Padding
    padding: number;

    // Typography override (optional per block)
    fontSize?: number;
    fontFamily?: string;
    color?: string;
    textAlign?: 'left' | 'center' | 'right' | 'justify';
}

export interface LayoutItem {
    id: LayoutSectionId;
    label: string;
    icon: string;
    isVisible: boolean;
    style: LayoutItemStyle;
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { InteractiveStoryData, LayoutSectionId, LayoutItem, ActiveComponent } from '../../types';
import { generateInteractiveStory } from '../../services/generators/readingStudio';
import { useAuth } from '../../context/AuthContext';
import { printService } from '../../utils/printService';
import { ImageDisplay, QUESTION_TYPES, StoryHighlighter } from '../sheets/common';
import { EditableText } from '../Editable';

// --- CONFIGURATION CONSTANTS ---
const SNAP_GRID = 5; // 5px precision grid
const A4_WIDTH_PX = 794; // approx 210mm @ 96dpi
const A4_HEIGHT_PX = 1123; // approx 297mm @ 96dpi

// --- DEFINITIONS & DEFAULTS ---

interface ComponentDefinition {
    id: LayoutSectionId;
    label: string;
    defaultTitle: string;
    icon: string;
    description: string;
    defaultStyle: Partial<LayoutItem['style']>;
}

interface ActiveComponent extends LayoutItem {
    customTitle?: string;
    customIcon?: string;
    themeColor?: string;
    instanceId: string; // Unique ID for multiples
}

const DEFAULT_STYLE_BASE: LayoutItem['style'] = {
    x: 20, y: 20, w: 754, h: 100, zIndex: 1,
    padding: 10,
    backgroundColor: 'transparent',
    borderColor: 'transparent',
    borderWidth: 0,
    borderRadius: 0,
    opacity: 1,
    boxShadow: 'none',
    textAlign: 'left',
    color: '#000000'
};

const COMPONENT_DEFINITIONS: ComponentDefinition[] = [
    { id: 'header', label: 'Başlık Künyesi', defaultTitle: 'HİKAYE KÜNYESİ', icon: 'fa-heading', description: 'Başlık, tür ve tarih alanı.', defaultStyle: { h: 120 } },
    { id: 'tracker', label: 'Okuma Takipçisi', defaultTitle: 'OKUMA TAKİBİ', icon: 'fa-eye', description: 'Okuma sayısını işaretleme alanı.', defaultStyle: { h: 60, w: 200 } },
    { id: 'story_block', label: 'Hikaye Metni', defaultTitle: 'OKUMA METNİ', icon: 'fa-book-open', description: 'Ana metin ve görsel alanı.', defaultStyle: { h: 400 } },
    { id: 'vocabulary', label: 'Sözlükçe', defaultTitle: 'SÖZLÜKÇE', icon: 'fa-spell-check', description: 'Zor kelimeler ve anlamları.', defaultStyle: { h: 150 } },
    { id: 'questions_5n1k', label: '5N 1K Analizi', defaultTitle: '5N 1K SORULARI', icon: 'fa-circle-question', description: 'Kim, Ne, Nerede soruları.', defaultStyle: { w: 370, h: 300 } },
    { id: 'questions_test', label: 'Test Soruları', defaultTitle: 'DEĞERLENDİRME', icon: 'fa-list-check', description: 'Çoktan seçmeli sorular.', defaultStyle: { w: 370, h: 300 } },
    { id: 'questions_inference', label: 'Derin Analiz', defaultTitle: 'DERİN ANALİZ', icon: 'fa-brain', description: 'Çıkarım ve yorum soruları.', defaultStyle: { h: 150 } },
    { id: 'creative', label: 'Yaratıcı Alan', defaultTitle: 'YARATICI ALAN', icon: 'fa-paintbrush', description: 'Çizim ve yazma alanı.', defaultStyle: { h: 200 } },
    { id: 'notes', label: 'Not Alanı', defaultTitle: 'NOTLAR', icon: 'fa-note-sticky', description: 'Boş not satırları.', defaultStyle: { h: 100 } },
];

// --- MICRO COMPONENTS ---

const ResizeHandle = ({ cursor, position, onMouseDown }: { cursor: string, position: string, onMouseDown: (e: React.MouseEvent) => void }) => (
    <div 
        className={`absolute w-3 h-3 bg-white border border-indigo-600 rounded-full z-50 hover:bg-indigo-600 hover:scale-125 transition-transform ${position}`}
        style={{ cursor }}
        onMouseDown={onMouseDown}
    />
);

const SettingsStation = ({ item, onUpdate, onClose, onDelete }: { item: ActiveComponent, onUpdate: (updates: Partial<ActiveComponent>) => void, onClose: () => void, onDelete: () => void }) => {

    const updateStyle = (key: keyof LayoutItem['style'], value: any) => {
        onUpdate({ style: { ...item.style, [key]: value } });
    };

    return (
        <div className="absolute right-4 top-4 bottom-4 w-72 bg-white/95 backdrop-blur-xl border-l border-zinc-200 shadow-2xl z-[100] flex flex-col rounded-2xl overflow-hidden animate-in slide-in-from-right-10 duration-300">
            {/* Header */}
            <div className="p-4 bg-zinc-100 border-b border-zinc-200 flex justify-between items-center">
                <h3 className="font-black text-xs uppercase tracking-widest text-zinc-600 flex items-center gap-2">
                    <i className={`fa-solid ${item.icon}`}></i> {item.label}
                </h3>
                <button onClick={onClose} className="w-6 h-6 rounded-full hover:bg-zinc-200 flex items-center justify-center text-zinc-400 transition-colors"><i className="fa-solid fa-times"></i></button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">

                {/* Dimensions */}
                <div className="space-y-3">
                    <label className="text-[10px] font-bold text-zinc-400 uppercase">Boyut & Konum</label>
                    <div className="grid grid-cols-2 gap-2">
                        <div className="flex items-center bg-zinc-50 border rounded px-2 py-1">
                            <span className="text-[10px] text-zinc-400 w-4">X</span>
                            <input type="number" value={item.style.x} onChange={e => updateStyle('x', Number(e.target.value))} className="w-full bg-transparent text-xs font-mono outline-none" />
                        </div>
                        <div className="flex items-center bg-zinc-50 border rounded px-2 py-1">
                            <span className="text-[10px] text-zinc-400 w-4">Y</span>
                            <input type="number" value={item.style.y} onChange={e => updateStyle('y', Number(e.target.value))} className="w-full bg-transparent text-xs font-mono outline-none" />
                        </div>
                        <div className="flex items-center bg-zinc-50 border rounded px-2 py-1">
                            <span className="text-[10px] text-zinc-400 w-4">W</span>
                            <input type="number" value={item.style.w} onChange={e => updateStyle('w', Number(e.target.value))} className="w-full bg-transparent text-xs font-mono outline-none" />
                        </div>
                        <div className="flex items-center bg-zinc-50 border rounded px-2 py-1">
                            <span className="text-[10px] text-zinc-400 w-4">H</span>
                            <input type="number" value={item.style.h} onChange={e => updateStyle('h', Number(e.target.value))} className="w-full bg-transparent text-xs font-mono outline-none" />
                        </div>
                    </div>
                </div>

                {/* Appearance */}
                <div className="space-y-3">
                    <label className="text-[10px] font-bold text-zinc-400 uppercase">Görünüm</label>
                    <div className="grid grid-cols-2 gap-2">
                        <div>
                            <span className="text-[9px] text-zinc-500 block mb-1">Arka Plan</span>
                            <div className="flex items-center gap-2 border rounded p-1">
                                <input type="color" value={item.style.backgroundColor === 'transparent' ? '#ffffff' : item.style.backgroundColor} onChange={e => updateStyle('backgroundColor', e.target.value)} className="w-6 h-6 rounded cursor-pointer border-0 p-0" />
                                <button onClick={() => updateStyle('backgroundColor', 'transparent')} className="text-[9px] px-1 bg-zinc-100 rounded">Yok</button>
                            </div>
                        </div>
                        <div>
                            <span className="text-[9px] text-zinc-500 block mb-1">Kenarlık</span>
                            <div className="flex items-center gap-2 border rounded p-1">
                                <input type="color" value={item.style.borderColor === 'transparent' ? '#000000' : item.style.borderColor} onChange={e => updateStyle('borderColor', e.target.value)} className="w-6 h-6 rounded cursor-pointer border-0 p-0" />
                                <input type="number" min="0" max="10" value={item.style.borderWidth} onChange={e => updateStyle('borderWidth', Number(e.target.value))} className="w-8 text-xs bg-zinc-50 rounded" />
                            </div>
                        </div>
                    </div>
                    <div>
                        <span className="text-[9px] text-zinc-500 block mb-1">Köşe Yuvarlaklığı: {item.style.borderRadius}px</span>
                        <input type="range" min="0" max="50" value={item.style.borderRadius || 0} onChange={e => updateStyle('borderRadius', Number(e.target.value))} className="w-full h-1 bg-zinc-200 rounded-lg appearance-none cursor-pointer accent-indigo-600" />
                    </div>
                    <div>
                        <span className="text-[9px] text-zinc-500 block mb-1">Gölge</span>
                        <div className="flex bg-zinc-50 rounded p-1 gap-1">
                             {['none', 'sm', 'md', 'lg'].map(s => (
                                 <button key={s} onClick={() => updateStyle('boxShadow', s)} className={`flex-1 text-[9px] py-1 rounded ${item.style.boxShadow === s ? 'bg-white shadow text-black font-bold' : 'text-zinc-500'}`}>{s.toUpperCase()}</button>
                             ))}
                        </div>
                    </div>
                </div>

                {/* Layering */}
                <div className="space-y-3">
                    <label className="text-[10px] font-bold text-zinc-400 uppercase">Katman</label>
                    <div className="flex gap-2">
                        <button onClick={() => updateStyle('zIndex', (item.style.zIndex || 0) + 1)} className="flex-1 py-1.5 bg-zinc-100 hover:bg-zinc-200 rounded text-xs font-bold text-zinc-600">Öne Getir</button>
                        <button onClick={() => updateStyle('zIndex', Math.max(0, (item.style.zIndex || 0) - 1))} className="flex-1 py-1.5 bg-zinc-100 hover:bg-zinc-200 rounded text-xs font-bold text-zinc-600">Arkaya İt</button>
                    </div>
                </div>

                {/* Component Specific */}
                <div className="space-y-3 pt-4 border-t border-zinc-100">
                    <label className="text-[10px] font-bold text-zinc-400 uppercase">İçerik Ayarları</label>
                    <div>
                        <span className="text-[9px] text-zinc-500 block mb-1">Başlık</span>
                        <input type="text" value={item.customTitle || ''} onChange={e => onUpdate({customTitle: e.target.value})} className="w-full p-2 border rounded bg-zinc-50 text-xs font-bold" />
                    </div>
                    <div className="flex gap-2">
                        <div className="flex-1">
                            <span className="text-[9px] text-zinc-500 block mb-1">Tema Rengi</span>
                            <input type="color" value={item.themeColor || '#000000'} onChange={e => onUpdate({themeColor: e.target.value})} className="w-full h-8 rounded cursor-pointer border" />
                        </div>
                        <div className="flex-1">
                            <span className="text-[9px] text-zinc-500 block mb-1">Metin Hizala</span>
                            <div className="flex bg-zinc-50 rounded border p-1">
                                {['left', 'center', 'right'].map((align: any) => (
                                    <button key={align} onClick={() => updateStyle('textAlign', align)} className={`flex-1 flex justify-center text-xs ${item.style.textAlign === align ? 'text-black font-bold' : 'text-zinc-400'}`}>
