                                    <button 
                                        key={def.id}
                                        onClick={() => addComponent(def)}
                                        className="w-full flex items-center gap-3 p-3 bg-zinc-50 hover:bg-indigo-50 border border-zinc-100 hover:border-indigo-200 rounded-xl transition-all group text-left"
