                <div className="flex-1 space-y-2 overflow-hidden">
                    {storyData ? (
                        [1,2,3].map(i => <div key={i} className="h-2 bg-zinc-100 rounded w-full"></div>)
                    ) : <p className="text-[10px] text-zinc-400 italic">Soru alanı...</p>}
