                    imgWrapperClass = `float-left mr-4 mb-2 z-10 relative`;
                    imgContainerStyle = { ...imgContainerStyle, width: `${imgSettings.widthPercent}%` };
                } else { // Right (default)
                    imgWrapperClass = `float-right ml-4 mb-2 z-10 relative`;
                    imgContainerStyle = { ...imgContainerStyle, width: `${imgSettings.widthPercent}%` };
