                                        <button key={align} onClick={() => updateStyle('textAlign', align)} className={`flex-1 h-8 flex items-center justify-center rounded text-xs transition-colors ${item.style.textAlign === align ? 'bg-white shadow text-indigo-600' : 'text-zinc-400 hover:text-zinc-600'}`}>
                                            <i className={`fa-solid fa-align-${align}`}></i>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                )}

            </div>

            <div className="p-4 border-t border-zinc-200 bg-zinc-50 shrink-0">
                <button onClick={onDelete} className="w-full py-2.5 bg-red-50 text-red-600 hover:bg-red-100 border border-red-200 rounded-xl font-bold text-xs transition-colors flex items-center justify-center gap-2">
                    <i className="fa-solid fa-trash"></i> Bileşeni Sil
                </button>
            </div>
        </div>
    );
}

