                                                <ResizeHandle cursor="nw-resize" position="-top-1.5 -left-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'nw')} />
                                                <ResizeHandle cursor="n-resize" position="-top-1.5 left-1/2 -translate-x-1/2" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'n')} />
                                                <ResizeHandle cursor="ne-resize" position="-top-1.5 -right-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'ne')} />
                                                <ResizeHandle cursor="e-resize" position="top-1/2 -translate-y-1/2 -right-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'e')} />
                                                <ResizeHandle cursor="se-resize" position="-bottom-1.5 -right-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'se')} />
                                                <ResizeHandle cursor="s-resize" position="-bottom-1.5 left-1/2 -translate-x-1/2" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 's')} />
                                                <ResizeHandle cursor="sw-resize" position="-bottom-1.5 -left-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'sw')} />
                                                <ResizeHandle cursor="w-resize" position="top-1/2 -translate-y-1/2 -left-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'w')} />
                                            </div>
                                        </div>
                                    )}

                                    {/* Content Render */}
                                    <div className="w-full h-full overflow-hidden pointer-events-none">
                                        {renderContent(item)}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* SETTINGS STATION (RIGHT PANEL) */}
                {selectedId && showSettings && (
                    <SettingsStation 
                        item={layout.find(l => l.instanceId === selectedId)!} 
                        onUpdate={updateItem} 
                        onClose={() => setShowSettings(false)}
                        onDelete={deleteItem}
                    />
                )}
            </div>
        </div>
    );
};

