                    className="flex-1 bg-zinc-100 dark:bg-zinc-950 overflow-auto flex justify-center p-8 relative custom-scrollbar"
                    onClick={() => { setSelectedId(null); setShowSettings(false); }}
                >
                    <div 
                        id="canvas-root"
                        className="bg-white shadow-2xl relative transition-all duration-300"
                        style={{ width: `${A4_WIDTH_PX}px`, height: `${A4_HEIGHT_PX}px`, transform: 'scale(1)', transformOrigin: 'top center' }}
                    >
                        {/* Background Grid for Precision */}
                        {designMode && (
                            <div className="absolute inset-0 pointer-events-none z-0" 
                                style={{backgroundImage: `radial-gradient(#e5e7eb 1px, transparent 1px)`, backgroundSize: `${SNAP_GRID * 4}px ${SNAP_GRID * 4}px`}}>
                            </div>
                        )}

                        {layout.map((item) => {
                            const isSelected = selectedId === item.instanceId;

                            return (
                                <div
                                    key={item.instanceId}
                                    onMouseDown={(e) => handleMouseDown(e, item.instanceId)}
                                    className={`absolute transition-shadow duration-75 ${designMode ? 'hover:ring-1 hover:ring-indigo-300 cursor-move' : ''}`}
                                    style={{
                                        left: item.style.x,
                                        top: item.style.y,
                                        width: item.style.w,
                                        height: item.style.h,
                                        zIndex: item.style.zIndex,
                                        padding: item.style.padding,
                                        backgroundColor: item.style.backgroundColor,
                                        borderColor: item.style.borderColor,
                                        borderWidth: item.style.borderWidth,
                                        borderRadius: item.style.borderRadius,
                                        boxShadow: item.style.boxShadow === 'none' ? 'none' : `var(--shadow-${item.style.boxShadow})`
                                    }}
                                >
                                    {/* Selection Frame */}
                                    {designMode && isSelected && (
                                        <div className="absolute inset-0 border-2 border-indigo-600 z-50 pointer-events-none">
                                            {/* Info Badge */}
                                            <div className="absolute -top-6 left-0 bg-indigo-600 text-white text-[9px] px-2 py-0.5 rounded-t font-bold uppercase tracking-widest whitespace-nowrap">
                                                {item.label} • {item.style.w}x{item.style.h}
                                            </div>
                                            {/* Resize Handles */}
                                            <div className="pointer-events-auto">
                                                <ResizeHandle cursor="nw-resize" position="-top-1.5 -left-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'nw')} />
                                                <ResizeHandle cursor="n-resize" position="-top-1.5 left-1/2 -translate-x-1/2" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'n')} />
                                                <ResizeHandle cursor="ne-resize" position="-top-1.5 -right-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'ne')} />
                                                <ResizeHandle cursor="e-resize" position="top-1/2 -translate-y-1/2 -right-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'e')} />
                                                <ResizeHandle cursor="se-resize" position="-bottom-1.5 -right-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'se')} />
                                                <ResizeHandle cursor="s-resize" position="-bottom-1.5 left-1/2 -translate-x-1/2" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 's')} />
                                                <ResizeHandle cursor="sw-resize" position="-bottom-1.5 -left-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'sw')} />
                                                <ResizeHandle cursor="w-resize" position="top-1/2 -translate-y-1/2 -left-1.5" onMouseDown={(e) => handleMouseDown(e, item.instanceId, 'w')} />
                                            </div>
                                        </div>
                                    )}

                                    {/* Content Render */}
                                    <div className="w-full h-full overflow-hidden pointer-events-none">
                                        {renderContent(item)}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* SETTINGS STATION (RIGHT PANEL) */}
                {selectedId && showSettings && (
                    <SettingsStation 
                        item={layout.find(l => l.instanceId === selectedId)!} 
                        onUpdate={updateItem} 
                        onClose={() => setShowSettings(false)}
                        onDelete={deleteItem}
                    />
                )}
            </div>
        </div>
    );
};

