                                            placeholder="Örn: Uzay Macerası"
                                        />
                                    </div>

                                    <div className="grid grid-cols-2 gap-3">
                                        <div>
                                            <label className="block text-xs font-bold text-zinc-600 mb-1">Sınıf</label>
                                            <select 
                                                value={config.gradeLevel} 
