                     ))}
                 </div>
            </div>
        );
    }

    return <div className="text-zinc-400 text-xs italic p-2 bg-zinc-50 rounded">Bu bileşen için özel içerik ayarı yok. Stil sekmesini kullanın.</div>;
};

