                {activeTab === 'look' && <AppearanceControls style={item.style} onUpdate={updateStyle} />}

                {activeTab === 'layout' && (
                    <div className="space-y-4 animate-in fade-in">
                        {/* Existing Layout Controls */}
                        <div className="grid grid-cols-2 gap-3">
                                {['x', 'y', 'w', 'h', 'rotation'].map((key) => (
