                {/* CANVAS */}
                <div className="flex-1 bg-zinc-100 dark:bg-zinc-950 overflow-auto flex justify-center relative custom-scrollbar" onClick={(e) => { if(e.target === e.currentTarget) setSelectedId(null); }}>
