                    value={data.task} 
                    onChange={e => onUpdateSpecific({...data, task: e.target.value})} 
                    className="w-full h-32 p-2 bg-zinc-800 border border-zinc-700 rounded text-sm text-zinc-200 focus:border-amber-500 outline-none resize-none"
