                         </div>
                     ))}
                 </div>
            </div>
        );
    }

    // CREATIVE SPECIFIC
    if (item.id === 'creative') {
        const data = item.specificData || { task: "Hikayeyle ilgili bir resim çiz." };
        return (
             <div className="space-y-3">
                <label className="text-[10px] font-bold text-zinc-400 uppercase block mb-1">Yaratıcı Görev Yönergesi</label>
